const BY_NAME = new Map<string, HydrasynthNrpn>();
for (const e of HYDRASYNTH_NRPNS) {
  BY_NAME.set(e.name, e);
  if (e.aliases) for (const a of e.aliases) BY_NAME.set(a, e);
}

// Normalized lookup table: strip non-alphanumerics from every canonical
// name and alias so callers passing abbreviated or punctuation-stripped
// variants ("filter1res" instead of "filter1.res" or "filter1resonance")
// still resolve to the canonical entry. Closes the 2026-05-24 regression
// where list_params advertised display_names like "filter1.res" but
// apply_patch rejected anything that wasn't the exact canonical name.
const NORMALIZED_BY_NAME = new Map<string, HydrasynthNrpn>();
function normalizeNrpnName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '');
}
for (const e of HYDRASYNTH_NRPNS) {
  NORMALIZED_BY_NAME.set(normalizeNrpnName(e.name), e);
  if (e.aliases) {
    for (const a of e.aliases) {
      const norm = normalizeNrpnName(a);
      // Only set if not already populated by a different entry — avoids
      // ambiguous aliases stealing a canonical normalized key.
      if (!NORMALIZED_BY_NAME.has(norm)) NORMALIZED_BY_NAME.set(norm, e);
    }
  }
}

/**
 * Lookup by canonical name OR alias OR punctuation-stripped form.
 * Resolution order:
 *   1. Exact canonical name ("filter1resonance")
 *   2. Exact alias ("filter1.res")
 *   3. Punctuation-stripped match ("filter1res", "mixer_osc1_vol", etc.)
 *
 * Aliases include the matching CC-catalog id when one exists (e.g.
 * "mixer.osc1_vol", "env1.attack", "filter1.res") so callers don't have
 * to know which naming convention the NRPN map uses internally.
 */
export function findHydraNrpn(name: string): HydrasynthNrpn | undefined {
  const direct = BY_NAME.get(name);
  if (direct !== undefined) return direct;
  return NORMALIZED_BY_NAME.get(normalizeNrpnName(name));
}
